const useEffect = React.useEffect;
const useMemo = React.useMemo;
const useRef = React.useRef;
const useState = React.useState;

const hasLegacyAdapter = () => (
	typeof legacyNativeCmder !== 'undefined'
	&& typeof legacyNativeCmder?._envAdapter?.callAdapter === 'function'
);

const hasChannelCall = () => (
	typeof channel !== 'undefined'
	&& typeof channel.call === 'function'
);

const normalizeNumber = (value) => {
	const numericValue = Number(value);
	return Number.isFinite(numericValue) ? numericValue : 0;
};

const clamp = (value, min, max) => Math.min(max, Math.max(min, value));

const normalizeVolumeValue = (value) => {
	const numericValue = Number(value);
	if (!Number.isFinite(numericValue)) {
		return null;
	}
	if (numericValue >= 0 && numericValue <= 1) {
		return numericValue;
	}
	if (numericValue > 1 && numericValue <= 100) {
		return numericValue / 100;
	}
	return null;
};

const formatTime = (value) => {
	const totalSeconds = Math.max(0, Math.floor(normalizeNumber(value)));
	const hours = Math.floor(totalSeconds / 3600);
	const minutes = Math.floor((totalSeconds % 3600) / 60);
	const seconds = totalSeconds % 60;

	if (hours > 0) {
		return `${hours}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
	}

	return `${minutes}:${String(seconds).padStart(2, '0')}`;
};

const getDurationFromPlayingSong = () => {
	const playingSong = getPlayingSong();
	const durationCandidates = [
		playingSong?.duration,
		playingSong?.dt,
		playingSong?.resourceDuration,
		playingSong?.curTrack?.duration,
		playingSong?.curTrack?.dt,
		playingSong?.data?.duration,
		playingSong?.data?.dt,
	];

	for (const candidate of durationCandidates) {
		const numericValue = normalizeNumber(candidate);
		if (numericValue <= 0) {
			continue;
		}

		return numericValue > 1000 ? numericValue / 1000 : numericValue;
	}

	return 0;
};

const getCurrentProgressFromPlayer = () => {
	const playingSong = getPlayingSong();
	const progressCandidates = [
		playingSong?.progress,
		playingSong?.playProgress,
		playingSong?.currentTime,
		playingSong?.time,
		playingSong?.curTrack?.progress,
		playingSong?.data?.progress,
	];

	for (const candidate of progressCandidates) {
		const numericValue = normalizeNumber(candidate);
		if (numericValue > 0) {
			return numericValue > 1000 ? numericValue / 1000 : numericValue;
		}
	}

	return 0;
};

const getCurrentVolumeFromPlayer = () => {
	try {
		const playerSettings = JSON.parse(localStorage.getItem('NM_SETTING_PLAYER') || '{}');
		const volume = [
			playerSettings?.volume,
			playerSettings?.vol,
			playerSettings?.volumeValue,
		].map(normalizeVolumeValue).find((candidate) => candidate !== null);
		if (volume !== undefined) {
			return volume;
		}
	} catch (error) {
		console.debug('Failed to read NM_SETTING_PLAYER.volume', error);
	}

	return null;
};

const getInitialVolume = () => {
	const volume = getCurrentVolumeFromPlayer();
	if (volume !== null) {
		return volume;
	}

	return 0.5;
};

const getVolumeFromEventArgs = (...args) => {
	for (const arg of [...args].reverse()) {
		const directVolume = normalizeVolumeValue(arg);
		if (directVolume !== null) {
			return directVolume;
		}

		if (arg && typeof arg === 'object') {
			const nestedVolume = [
				arg.volume,
				arg.vol,
				arg.value,
				arg.currentVolume,
			].map(normalizeVolumeValue).find((candidate) => candidate !== null);
			if (nestedVolume !== undefined) {
				return nestedVolume;
			}
		}
	}

	return null;
};

const genAudioPlayerCommand = (audioId, command) => {
	return `${audioId}|${command}|${Math.random().toString(36).slice(2, 8)}`;
};

const seekToProgress = (songId, progress) => {
	const normalizedSongId = String(songId || getPlayingSongId() || '').trim();
	if (!normalizedSongId) {
		return;
	}

	const normalizedProgress = Math.max(0, normalizeNumber(progress));
	if (hasLegacyAdapter()) {
		legacyNativeCmder._envAdapter.callAdapter('audioplayer.seek', () => {}, [
			normalizedSongId,
			genAudioPlayerCommand(normalizedSongId, 'seek'),
			normalizedProgress,
		]);
		return;
	}

	if (hasChannelCall()) {
		channel.call('audioplayer.seek', () => {}, [
			normalizedSongId,
			genAudioPlayerCommand(normalizedSongId, 'seek'),
			normalizedProgress,
		]);
	}
};

const setPlayerVolume = (volume) => {
	const normalizedVolume = clamp(normalizeNumber(volume), 0, 1);
	if (hasLegacyAdapter()) {
		legacyNativeCmder._envAdapter.callAdapter('audioplayer.setVolume', () => {}, ['', '', normalizedVolume]);
		return;
	}

	if (hasChannelCall()) {
		channel.call('audioplayer.setVolume', () => {}, ['', '', normalizedVolume]);
	}
};

const clickButton = (target) => {
	if (typeof target?.click !== 'function') {
		return false;
	}

	const eventInit = {
		bubbles: true,
		cancelable: true,
		view: window,
		button: 0,
	};
	const dispatchPointerEvent = (type, buttons) => {
		const EventConstructor = typeof PointerEvent === 'function' ? PointerEvent : MouseEvent;
		target.dispatchEvent(new EventConstructor(type, { ...eventInit, buttons, pointerType: 'mouse' }));
	};
	const dispatchMouseEvent = (type, buttons) => {
		target.dispatchEvent(new MouseEvent(type, { ...eventInit, buttons }));
	};

	dispatchPointerEvent('pointerdown', 1);
	dispatchMouseEvent('mousedown', 1);
	dispatchPointerEvent('pointerup', 0);
	dispatchMouseEvent('mouseup', 0);
	target.click();
	return Boolean(target);
};

const clickTransportButton = (action) => clickButton(getTransportButton(action));

const pausePlayback = () => {
	const playerButton = getPlayerButton();
	if (playerButton) {
		if (!isPlayerButtonPlaying(playerButton)) {
			return false;
		}

		return clickButton(getPlayingPlayerButton() || playerButton);
	}

	return clickTransportButton('play');
};

const resumePlayback = () => {
	const playerButton = getPlayerButton();
	if (playerButton) {
		if (isPlayerButtonPlaying(playerButton)) {
			return false;
		}

		return clickButton(getPausedPlayerButton() || playerButton);
	}

	return clickTransportButton('play');
};

const playPreviousSong = () => {
	return jumpToAdjacentTrack(-1) || clickTransportButton('previous');
};

const playNextSong = () => {
	return jumpToAdjacentTrack(1) || clickTransportButton('next');
};

