const getPlaybackModeLabel = (playMode) => {
	switch (playMode) {
		case PLAY_MODES.ORDER:
			return 'Order';
		case PLAY_MODES.REPEAT:
			return 'Repeat';
		case PLAY_MODES.AI:
			return 'AI';
		case PLAY_MODES.ONE:
			return 'Repeat one';
		case PLAY_MODES.RANDOM:
			return 'Shuffle';
		default:
			return 'Playback mode';
	}
};

const svgToMarkup = (svg) => (
	svg
		.replace(/>\s+</g, '><')
		.replace(/\sfill=(["'])(?:white|#FFFFFF)\1/gi, ' fill="currentColor"')
		.replace(/\sstroke=(["'])#00000000\1/gi, ' stroke="currentColor" stroke-opacity="0"')
		.trim()
);

