const PlaybackModeIcon = (props) => {
	switch (props.playMode) {
		case PLAY_MODES.ORDER:
			return <PlaybackOrderIcon />;
		case PLAY_MODES.REPEAT:
			return <PlaybackRepeatIcon />;
		case PLAY_MODES.AI:
			return <PlaybackAIIcon />;
		case PLAY_MODES.RANDOM:
			return <PlaybackRandomIcon />;
		case PLAY_MODES.ONE:
		default:
			return <PlaybackOneIcon />;
	}
};

const AudioQualityTag = (props) => {
	const asset = AUDIO_QUALITY_ICON_MAP[props.quality];
	return (
		<div
			className={`rnp-audio-quality${asset ? '' : ' is-empty'}${asset ? ` rnp-audio-quality-${props.quality}` : ''}`}
			aria-hidden={!asset}
			role={asset ? 'img' : undefined}
			aria-label={asset?.label}
			title={asset?.label}
		>
			{asset ? (
				<span
					className="rnp-audio-quality-icon"
					aria-hidden="true"
					dangerouslySetInnerHTML={{ __html: asset.markup }}
				/>
			) : null}
		</div>
	);
};

