function AmlLikePlayControls(props) {
	return (
		<div className="am-music-controls">
			<button
				type="button"
				className="am-music-track-btn rnp-amll-play-mode"
				onClick={props.onTogglePlayMode}
				aria-label={`Playback mode: ${getPlaybackModeLabel(props.playMode)}`}
				title={getPlaybackModeLabel(props.playMode)}
			>
				<PlaybackModeIcon playMode={props.playMode} />
			</button>
			<button
				type="button"
				className="am-music-track-prev"
				onClick={props.onPrevious}
				aria-label="Previous"
			>
				<PrevIcon />
			</button>
			<button
				type="button"
				className="am-music-play"
				onClick={props.onTogglePlay}
				aria-label={props.isPlaying ? 'Pause' : 'Play'}
			>
				{props.isPlaying ? <PauseIcon /> : <PlayIcon />}
			</button>
			<button
				type="button"
				className="am-music-track-next"
				onClick={props.onNext}
				aria-label="Next"
			>
				<NextIcon />
			</button>
			<button
				type="button"
				className="am-music-track-btn rnp-amll-playlist"
				onClick={props.onOpenPlaylist}
				aria-label="Playlist"
				title="Playlist"
			>
				<PlaylistIcon />
			</button>
		</div>
	);
}

export function V3PlayerControls(props) {
	const pageOpen = useRnpLyricPageOpen();
	const [songId, setSongId] = useState(getPlayingSongId());
	const [isPlaying, setIsPlaying] = useState(isPlayerPlaying());
	const [duration, setDuration] = useState(getDurationFromPlayingSong());
	const [progress, setProgress] = useState(getCurrentProgressFromPlayer());
	const [sliderValue, setSliderValue] = useState(getCurrentProgressFromPlayer());
	const [volume, setVolume] = useState(getInitialVolume());
	const [playMode, setPlayMode] = useState(getCurrentPlayMode());
	const [audioQuality, setAudioQuality] = useState(getCurrentAudioQuality());
	const [isFavorite, setIsFavorite] = useState(isCurrentSongLiked());
	const [isDragging, setIsDragging] = useState(false);
	const [progressPreviewAnchor, setProgressPreviewAnchor] = useState(null);
	const dragValueRef = useRef(sliderValue);
	const isDraggingRef = useRef(false);
	const isVolumeDraggingRef = useRef(false);
	const syncAccessoryState = () => {
		setPlayMode(getCurrentPlayMode());
		setAudioQuality(getCurrentAudioQuality());
		setIsFavorite(isCurrentSongLiked());
	};
	const syncAccessoryStateSoon = () => {
		[80, 180, 360, 700].forEach((delay) => {
			window.setTimeout(syncAccessoryState, delay);
		});
	};

	useEffect(() => {
		isDraggingRef.current = isDragging;
	}, [isDragging]);

	useEffect(() => {
		if (!pageOpen) return;
		const footer = document.querySelector('footer');
		const observer = new MutationObserver(syncAccessoryState);

		syncAccessoryState();
		if (footer) {
			observer.observe(footer, {
				attributes: true,
				attributeFilter: ['aria-label', 'aria-pressed', 'class', 'data-active', 'data-checked', 'data-state', 'title'],
				childList: true,
				subtree: true,
			});
		}
		appendRegisterCall('Load', 'audioplayer', syncAccessoryStateSoon);

		return () => {
			observer.disconnect();
			removeRegisterCall('Load', 'audioplayer', syncAccessoryStateSoon);
		};
	}, [pageOpen]);

	useEffect(() => {
		if (!pageOpen) return;
		const syncTrackState = () => {
			const currentSongId = getPlayingSongId();
			const currentDuration = getDurationFromPlayingSong();
			const currentProgress = getCurrentProgressFromPlayer();
			setSongId(currentSongId);
			setDuration(currentDuration);
			setIsPlaying(isPlayerPlaying());
			setAudioQuality(getCurrentAudioQuality());
			if (!isDraggingRef.current) {
				setProgress(currentProgress);
				setSliderValue(currentProgress);
				dragValueRef.current = currentProgress;
			}
		};
		const syncVolumeState = () => {
			const currentVolume = getCurrentVolumeFromPlayer();
			if (currentVolume !== null && !isVolumeDraggingRef.current) {
				setVolume(currentVolume);
			}
		};

		syncTrackState();
		syncVolumeState();

		const onPlayStateChange = (nextSongId, nextStateId) => {
			const nextIsPlaying = getIsPlayingFromPlayStateEvent(nextStateId ?? nextSongId);
			const resolvedSongId = nextStateId === undefined ? getPlayingSongId() : nextSongId;
			setSongId(String(resolvedSongId || getPlayingSongId() || '').trim());
			setIsPlaying(nextIsPlaying ?? isPlayerPlaying());
			setAudioQuality(getCurrentAudioQuality());
		};

		const onPlayProgressChange = (nextSongId, nextProgress) => {
			const normalizedSongId = String(nextSongId || getPlayingSongId() || '').trim();
			const normalizedProgress = Math.max(0, normalizeNumber(nextProgress));
			setSongId(normalizedSongId);
			setProgress(normalizedProgress);
			setDuration((currentDuration) => {
				const resolvedDuration = getDurationFromPlayingSong();
				return resolvedDuration > 0 ? resolvedDuration : currentDuration;
			});
			if (!isDraggingRef.current) {
				setSliderValue(normalizedProgress);
				dragValueRef.current = normalizedProgress;
			}
		};

		const onSongLoad = (nextSongId) => {
			const normalizedSongId = String(nextSongId || getPlayingSongId() || '').trim();
			const resolvedDuration = getDurationFromPlayingSong();
			setSongId(normalizedSongId);
			setDuration(resolvedDuration);
			setProgress(0);
			setIsPlaying(isPlayerPlaying());
			setAudioQuality(getCurrentAudioQuality());
			if (!isDraggingRef.current) {
				setSliderValue(0);
				dragValueRef.current = 0;
			}
		};

		const onVolumeChange = (...args) => {
			const nextVolume = getVolumeFromEventArgs(...args) ?? getCurrentVolumeFromPlayer();
			if (nextVolume !== null) {
				setVolume(nextVolume);
			}
		};

		appendRegisterCall('PlayState', 'audioplayer', onPlayStateChange);
		appendRegisterCall('PlayProgress', 'audioplayer', onPlayProgressChange);
		appendRegisterCall('Load', 'audioplayer', onSongLoad);
		appendRegisterCall('Volume', 'audioplayer', onVolumeChange);
		window.addEventListener('storage', syncVolumeState);
		const volumeSyncTimer = window.setInterval(syncVolumeState, 700);

		return () => {
			removeRegisterCall('PlayState', 'audioplayer', onPlayStateChange);
			removeRegisterCall('PlayProgress', 'audioplayer', onPlayProgressChange);
			removeRegisterCall('Load', 'audioplayer', onSongLoad);
			removeRegisterCall('Volume', 'audioplayer', onVolumeChange);
			window.removeEventListener('storage', syncVolumeState);
			window.clearInterval(volumeSyncTimer);
		};
	}, [pageOpen]);

	useEffect(() => {
		if (!isDragging) {
			setSliderValue(progress);
			dragValueRef.current = progress;
		}
	}, [isDragging, progress]);

	const sliderMax = useMemo(() => {
		return Math.max(duration, sliderValue, progress, 1);
	}, [duration, progress, sliderValue]);

	const remainText = useMemo(() => {
		return `-${formatTime(Math.max(duration - sliderValue, 0))}`;
	}, [duration, sliderValue]);

	const handleProgressChange = (nextValue) => {
		const normalizedValue = Math.max(0, normalizeNumber(nextValue));
		dragValueRef.current = normalizedValue;
		setSliderValue(normalizedValue);
	};

	const handleProgressCommit = (nextValue) => {
		const normalizedValue = Math.max(0, normalizeNumber(nextValue));
		dragValueRef.current = normalizedValue;
		setSliderValue(normalizedValue);
		setProgress(normalizedValue);
		setIsDragging(false);
		seekToProgress(songId, normalizedValue);
	};

	const handleVolumeChange = (nextValue) => {
		const normalizedValue = clamp(normalizeNumber(nextValue), 0, 1);
		setVolume(normalizedValue);
		setPlayerVolume(normalizedValue);
	};

	const handleVolumeCommit = (nextValue) => {
		isVolumeDraggingRef.current = false;
		handleVolumeChange(nextValue);
	};

	const syncPlaybackStateSoon = () => {
		window.setTimeout(() => {
			setIsPlaying(isPlayerPlaying());
		}, 120);
	};

	const handleTogglePlay = () => {
		const didClick = clickTransportButton('play');
		if (didClick) {
			setIsPlaying((currentPlaying) => !currentPlaying);
		}
		syncPlaybackStateSoon();
	};

	const handleTogglePlayMode = () => {
		if (clickButton(getPlayModeButton())) {
			syncAccessoryStateSoon();
		}
	};

	const handleToggleFavorite = () => {
		if (clickButton(getFavoriteButton())) {
			syncAccessoryStateSoon();
		}
	};

	const handleOpenPlaylist = () => {
		clickButton(getPlaylistButton());
	};

	return (
		<React.Fragment>
			<div className="rnp-v3-controls">
				<div className="am-music-progress-control">
					<V3Slider
						className="rnp-amll-progress-slider"
						min={0}
						max={sliderMax}
						value={Math.min(sliderValue, sliderMax)}
						onBeforeChange={() => setIsDragging(true)}
						onChange={handleProgressChange}
						onAfterChange={handleProgressCommit}
						trackRef={setProgressPreviewAnchor}
					/>
					<div className="am-music-progress-tips">
						<div>{formatTime(sliderValue)}</div>
						<AudioQualityTag quality={audioQuality} />
						<div>{remainText}</div>
					</div>
					{progressPreviewAnchor ? <ProgressbarPreview dom={progressPreviewAnchor} /> : null}
				</div>
				<AmlLikePlayControls
					isPlaying={isPlaying}
					playMode={playMode}
					onPrevious={() => {
						playPreviousSong();
					}}
					onTogglePlay={handleTogglePlay}
					onTogglePlayMode={handleTogglePlayMode}
					onOpenPlaylist={handleOpenPlaylist}
					onNext={() => {
						playNextSong();
					}}
				/>
				<div className="am-music-volume-controls">
					<V3Slider
						className="rnp-amll-volume-slider"
						min={0}
						max={1}
						step={0.01}
						value={volume}
						beforeIcon={<VolumeLowIcon />}
						afterIcon={<VolumeHighIcon />}
						onBeforeChange={() => {
							isVolumeDraggingRef.current = true;
						}}
						onChange={handleVolumeChange}
						onAfterChange={handleVolumeCommit}
					/>
				</div>
			</div>
			{props.coverFavoriteHost ? createPortal(
				<FavoriteButton
					isFavorite={isFavorite}
					onToggleFavorite={handleToggleFavorite}
				/>,
				props.coverFavoriteHost
			) : null}
		</React.Fragment>
	);
}
